import { injectJsFile } from "@/utils/utils.js";

//@ts-ignore
const useLogging = (ENVIRONMENT == "development");

export function bypassAdPlayback() {
    const adVideo = document.getElementsByClassName("ad-showing")[0] ||
        document.querySelector(".ytp-ad-text.ytp-ad-preview-text") ||
        document.querySelector("ytp-ad-preview-container");
    const video = document.getElementsByTagName("video")[0];
    if (adVideo != undefined && video != undefined) {
        useLogging && console.log("BAP: Speeding through ad", adVideo);
        if (video.dataset.bgAdSkipActive !== "true") {
            // Use proactively saved rate (from before YouTube reset it for the ad),
            // falling back to current value if no proactive save exists yet
            video.dataset.bgPreAdPlaybackRate = video.dataset.bgUserRate || String(video.playbackRate);
            video.dataset.bgPreAdMuted = video.dataset.bgUserMuted || String(video.muted);
            video.dataset.bgPreAdOpacity = video.style.opacity;
        }
        video.dataset.bgAdSkipActive = "true";
        video.muted = true;
        video.playbackRate = 16;
        video.style.opacity = "0";
        if (video.paused) {
            video.play();
        }
    } else if (video != undefined && video.dataset.bgAdSkipActive === "true") {
        useLogging && console.log("BAP: Ad finished, restoring playback");
        const savedRate = parseFloat(video.dataset.bgPreAdPlaybackRate) || 1;
        video.style.opacity = video.dataset.bgPreAdOpacity || "";
        video.playbackRate = savedRate;
        video.muted = video.dataset.bgPreAdMuted === "true";
        delete video.dataset.bgAdSkipActive;
        delete video.dataset.bgPreAdMuted;
        delete video.dataset.bgPreAdPlaybackRate;
        delete video.dataset.bgPreAdOpacity;
        // Set rate via YouTube's player API to sync its internal state.
        // Direct video.playbackRate changes get overridden by YouTube's player.
        injectJsFile("injection-youtube-rate.js", { rate: savedRate });
    } else if (video != undefined) {
        // Proactively track user's playback state on every tick when no ad is playing.
        // YouTube resets video.playbackRate to 1 for ads BEFORE adding ad indicators,
        // so we can't rely on the rate at ad-detection time.
        const currentRate = String(video.playbackRate);
        const currentMuted = String(video.muted);
        if (video.dataset.bgUserRate !== currentRate) {
            video.dataset.bgUserRate = currentRate;
        }
        if (video.dataset.bgUserMuted !== currentMuted) {
            video.dataset.bgUserMuted = currentMuted;
        }
    }
}

const youtubeAdTags = [
    {"tag": "ytd-rich-item-renderer ytd-ad-slot-renderer", "remove": true, "refresh": false, "parentLevel": 2},
    {"tag": ".ytd-ad-slot-renderer", "remove": true, "refresh": false},
    {"tag": "tp-yt-iron-overlay-backdrop", "remove": true, "refresh": false,
        "addClasses": ["opened"],
        "removeClasses": ["closed"],
    },
    {"tag": "#movie_player", "remove": false, "refresh": false,
        "addClasses": ["ad-created", "playing-mode"],
        "removeClasses": [
            "ad-interrupting",
            "ytp-hide-controls",
            "ytp-ad-display-override",
            "ended-mode",
            "unstarted-mode",
            "paused-mode",
        ]},
];

export function processYoutubeAds() {

    for (const ad of youtubeAdTags) {
        let elements = document.querySelectorAll(ad.tag);
        if (elements.length === 0) {
            continue;
        }
        if (ad.remove) {
            useLogging && console.log("Removing: ", ad.tag);
            elements.forEach((e) =>  {
                if (ad.parentLevel) {
                    let backCount = ad.parentLevel || 1;
                    while (backCount > 0) {
                        e = e.parentNode;
                        backCount--;
                    }
                }
                e.remove();
            });
        }
        if (ad.removeClasses) {
            elements.forEach((e) => e.classList.remove(...ad.removeClasses));
        }
        if (ad.addClasses) {
            elements.forEach((e) => e.classList.add(...ad.addClasses));
        }
        if (ad.refresh) {
            useLogging && console.log("Refreshing: ", ad.tag);
            window.location.reload();
        }
    }
    bypassAdPlayback();
}
